# Generated by openai (gpt-5.2)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
  agent any

  options {
    timestamps()
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30'))
    skipDefaultCheckout(true)
    timeout(time: 60, unit: 'MINUTES')
  }

  parameters {
    choice(
      name: 'ARTIFACT_TYPE',
      choices: ['generic', 'tar.gz', 'zip', 'jar', 'war', 'rpm', 'deb'],
      description: 'Used for naming/extraction behavior. "generic" means no extraction.'
    )

    text(
      name: 'ARTIFACT_URLS',
      defaultValue: '',
      description: 'One URL per line. Supports: https/http, s3://bucket/key, artifactory://repo/path or https(s) Artifactory URLs.'
    )

    string(
      name: 'ARTIFACT_USERNAME',
      defaultValue: '',
      description: 'Optional: Username for HTTP/Artifactory basic auth.'
    )

    password(
      name: 'ARTIFACT_PASSWORD',
      defaultValue: '',
      description: 'Optional: Password/API key for HTTP/Artifactory basic auth.'
    )

    string(
      name: 'AWS_REGION',
      defaultValue: 'us-east-1',
      description: 'AWS region for S3 downloads (if using s3:// URLs).'
    )

    choice(
      name: 'DEPLOY_METHOD',
      choices: ['ssh', 'scp', 'rsync'],
      description: 'How to copy artifacts to servers.'
    )

    string(
      name: 'PROD_SERVERS',
      defaultValue: '',
      description: 'Comma or newline separated list of production servers (hostnames/IPs).'
    )

    string(
      name: 'SSH_USER',
      defaultValue: 'deploy',
      description: 'SSH user for production servers.'
    )

    credentials(
      name: 'SSH_CREDENTIALS_ID',
      defaultValue: '',
      description: 'Jenkins credentials ID for SSH private key.'
    )

    string(
      name: 'REMOTE_DEPLOY_DIR',
      defaultValue: '/opt/app/releases',
      description: 'Remote directory where artifacts will be uploaded.'
    )

    booleanParam(
      name: 'EXTRACT_ON_SERVER',
      defaultValue: false,
      description: 'If true and artifact is zip/tar.gz, extracts on the server.'
    )

    string(
      name: 'REMOTE_SYMLINK_PATH',
      defaultValue: '/opt/app/current',
      description: 'If set, will point this symlink to the newly deployed directory (per server). Leave blank to skip.'
    )

    string(
      name: 'REMOTE_POST_DEPLOY_CMD',
      defaultValue: '',
      description: 'Optional command to run on each server after upload/extract (e.g., systemctl restart app).'
    )

    booleanParam(
      name: 'DRY_RUN',
      defaultValue: false,
      description: 'If true, prints actions but does not upload/execute remote changes.'
    )

    booleanParam(
      name: 'PARALLEL_DEPLOY',
      defaultValue: true,
      description: 'Deploy to servers in parallel.'
    )
  }

  environment {
    WORK_DL_DIR = "${WORKSPACE}/downloaded_artifacts"
    WORK_STG_DIR = "${WORKSPACE}/staged_artifacts"
    CURL_OPTS = "-fL --retry 3 --retry-delay 2 --connect-timeout 15 --max-time 1800"
  }

  stages {
    stage('Validate Inputs') {
      steps {
        script {
          def urls = (params.ARTIFACT_URLS ?: '')
            .split(/\r?\n/)
            .collect { it.trim() }
            .findAll { it }

          if (urls.isEmpty()) {
            error("ARTIFACT_URLS is empty. Provide one or more artifact URLs (one per line).")
          }

          def servers = (params.PROD_SERVERS ?: '')
            .split(/[\r?\n,]+/)
            .collect { it.trim() }
            .findAll { it }

          if (servers.isEmpty()) {
            error("PROD_SERVERS is empty. Provide one or more servers (comma or newline separated).")
          }

          if (!params.SSH_CREDENTIALS_ID?.trim()) {
            error("SSH_CREDENTIALS_ID is required.")
          }

          if (!params.REMOTE_DEPLOY_DIR?.trim()) {
            error("REMOTE_DEPLOY_DIR is required.")
          }

          currentBuild.description = "Artifacts: ${urls.size()} | Servers: ${servers.size()} | DryRun: ${params.DRY_RUN}"
        }
      }
    }

    stage('Prepare Workspace') {
      steps {
        sh """
          set -euo pipefail
          rm -rf "${WORK_DL_DIR}" "${WORK_STG_DIR}"
          mkdir -p "${WORK_DL_DIR}" "${WORK_STG_DIR}"
        """
      }
    }

    stage('Download Artifacts') {
      steps {
        script {
          def urls = (params.ARTIFACT_URLS ?: '')
            .split(/\r?\n/)
            .collect { it.trim() }
            .findAll { it }

          withEnv(["AWS_DEFAULT_REGION=${params.AWS_REGION}"]) {
            def i = 0
            for (u in urls) {
              i++
              def safeName = u.replaceAll(/[^\w.\-]+/, "_")
              def out = "${env.WORK_DL_DIR}/artifact_${String.format('%03d', i)}_${safeName}"
              sh """
                set -euo pipefail
                echo "Downloading: ${u}"
                case "${u}" in
                  s3://*)
                    if ! command -v aws >/dev/null 2>&1; then
                      echo "ERROR: aws CLI not found but required for s3:// downloads"
                      exit 2
                    fi
                    aws s3 cp "${u}" "${out}"
                    ;;
                  artifactory://*)
                    # Transform artifactory://repo/path -> use ARTIFACTORY_BASE_URL if set, else error
                    if [ -z "${ARTIFACTORY_BASE_URL:-}" ]; then
                      echo "ERROR: ARTIFACTORY_BASE_URL env var must be set for artifactory:// URLs"
                      exit 2
                    fi
                    REL="\${u#artifactory://}"
                    URL="${ARTIFACTORY_BASE_URL%/}/\${REL}"
                    if [ -n "${params.ARTIFACT_USERNAME}".trim() ] && [ -n "${params.ARTIFACT_PASSWORD}".trim() ]; then
                      curl ${env.CURL_OPTS} -u "${params.ARTIFACT_USERNAME}:${params.ARTIFACT_PASSWORD}" -o "${out}" "\${URL}"
                    else
                      curl ${env.CURL_OPTS} -o "${out}" "\${URL}"
                    fi
                    ;;
                  http://*|https://*)
                    if [ -n "${params.ARTIFACT_USERNAME}".trim() ] && [ -n "${params.ARTIFACT_PASSWORD}".trim() ]; then
                      curl ${env.CURL_OPTS} -u "${params.ARTIFACT_USERNAME}:${params.ARTIFACT_PASSWORD}" -o "${out}" "${u}"
                    else
                      curl ${env.CURL_OPTS} -o "${out}" "${u}"
                    fi
                    ;;
                  *)
                    echo "ERROR: Unsupported URL scheme: ${u}"
                    exit 2
                    ;;
                esac

                if [ ! -s "${out}" ]; then
                  echo "ERROR: Downloaded file is empty: ${out}"
                  exit 2
                fi

                echo "Saved: ${out}"
              """
            }
          }
        }
      }
    }

    stage('Stage & Verify') {
      steps {
        sh """
          set -euo pipefail
          ls -lah "${WORK_DL_DIR}"
          for f in "${WORK_DL_DIR}"/*; do
            [ -f "$f" ] || continue
            sha256sum "$f" | tee -a "${WORK_STG_DIR}/SHA256SUMS"
          done
          cp -a "${WORK_DL_DIR}/." "${WORK_STG_DIR}/"
          echo "Staged artifacts:"
          ls -lah "${WORK_STG_DIR}"
          echo "Checksums:"
          cat "${WORK_STG_DIR}/SHA256SUMS"
        """
      }
    }

    stage('Deploy to Production') {
      steps {
        script {
          def servers = (params.PROD_SERVERS ?: '')
            .split(/[\r?\n,]+/)
            .collect { it.trim() }
            .findAll { it }

          def releaseId = new Date().format("yyyyMMdd_HHmmss", TimeZone.getTimeZone('UTC')) + "_${env.BUILD_NUMBER}"
          def remoteReleaseDir = "${params.REMOTE_DEPLOY_DIR}".replaceAll(/\/+$/, '') + "/${releaseId}"

          def deployOne = { String host ->
            sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
              def remote = "${params.SSH_USER}@${host}"

              sh """
                set -euo pipefail
                echo "---- Deploying to ${host} ----"

                if ${params.DRY_RUN}; then
                  echo "[DRY_RUN] Would create remote directory: ${remoteReleaseDir}"
                else
                  ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new "${remote}" "mkdir -p '${remoteReleaseDir}'"
                fi

                if ${params.DRY_RUN}; then
                  echo "[DRY_RUN] Would upload artifacts from ${WORK_STG_DIR} to ${remote}:${remoteReleaseDir}"
                else
                  case "${params.DEPLOY_METHOD}" in
                    ssh)
                      # Stream a tarball over SSH to avoid multiple scp calls
                      tar -C "${WORK_STG_DIR}" -czf - . | ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new "${remote}" "tar -xzf - -C '${remoteReleaseDir}'"
                      ;;
                    scp)
                      scp -o BatchMode=yes -o StrictHostKeyChecking=accept-new -r "${WORK_STG_DIR}/." "${remote}:'${remoteReleaseDir}/'"
                      ;;
                    rsync)
                      if ! command -v rsync >/dev/null 2>&1; then
                        echo "ERROR: rsync not found but DEPLOY_METHOD=rsync"
                        exit 2
                      fi
                      rsync -az --delete -e "ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new" "${WORK_STG_DIR}/" "${remote}:'${remoteReleaseDir}/'"
                      ;;
                    *)
                      echo "ERROR: Unknown DEPLOY_METHOD: ${params.DEPLOY_METHOD}"
                      exit 2
                      ;;
                  esac
                fi

                if ${params.DRY_RUN}; then
                  echo "[DRY_RUN] Would verify checksums on server"
                else
                  ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new "${remote}" "cd '${remoteReleaseDir}' && sha256sum -c SHA256SUMS"
                fi

                if ${params.EXTRACT_ON_SERVER}; then
                  if ${params.DRY_RUN}; then
                    echo "[DRY_RUN] Would extract archives on server (zip/tar.gz)"
                  else
                    ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new "${remote}" "set -euo pipefail; cd '${remoteReleaseDir}'; for a in *; do [ -f \"\\\$a\" ] || continue; case \"\\\$a\" in *.tar.gz|*.tgz) mkdir -p extracted && tar -xzf \"\\\$a\" -C extracted ;; *.zip) mkdir -p extracted && unzip -o \"\\\$a\" -d extracted >/dev/null ;; esac; done"
                  fi
                fi

                if [ -n "${params.REMOTE_SYMLINK_PATH}".trim() ]; then
                  if ${params.DRY_RUN}; then
                    echo "[DRY_RUN] Would update symlink ${params.REMOTE_SYMLINK_PATH} -> ${remoteReleaseDir}"
                  else
                    ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new "${remote}" "ln -sfn '${remoteReleaseDir}' '${params.REMOTE_SYMLINK_PATH}'"
                  fi
                fi

                if [ -n "${params.REMOTE_POST_DEPLOY_CMD}".trim() ]; then
                  if ${params.DRY_RUN}; then
                    echo "[DRY_RUN] Would run post-deploy command: ${params.REMOTE_POST_DEPLOY_CMD}"
                  else
                    ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new "${remote}" "cd '${remoteReleaseDir}' && ${params.REMOTE_POST_DEPLOY_CMD}"
                  fi
                fi

                echo "---- Done: ${host} ----"
              """
            }
          }

          if (params.PARALLEL_DEPLOY && servers.size() > 1) {
            def fanout = [:]
            for (s in servers) {
              def host = s
              fanout[host] = { deployOne(host) }
            }
            parallel fanout
          } else {
            for (s in servers) deployOne(s)
          }
        }
      }
    }
  }

  post {
    always {
      archiveArtifacts artifacts: 'staged_artifacts/**', allowEmptyArchive: true, fingerprint: true
    }
    failure {
      script {
        currentBuild.description = (currentBuild.description ?: '') + " | FAILED"
      }
    }
    success {
      script {
        currentBuild.description = (currentBuild.description ?: '') + " | SUCCESS"
      }
    }
    cleanup {
      cleanWs(deleteDirs: true, disableDeferredWipeout: true)
    }
  }
}